import React, { useState } from 'react';
import { Play, Pause, ChevronRight, Mic, Volume2, Sparkles, ChevronDown, ChevronUp } from 'lucide-react';
import { VoiceBrief } from '../types';

interface VoiceBriefingProps {
  brief: VoiceBrief;
}

export const VoiceBriefing: React.FC<VoiceBriefingProps> = ({ brief }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [showTranscript, setShowTranscript] = useState(false);

  return (
    <div className="bg-gradient-to-br from-indigo-900 via-slate-900 to-black rounded-2xl p-6 text-white shadow-xl relative overflow-hidden group">
      <div className="absolute top-0 right-0 p-4 opacity-10">
        <Mic size={120} />
      </div>

      <div className="relative z-10 flex flex-col md:flex-row gap-6 items-start md:items-center">
        {/* Play Button */}
        <button 
          onClick={() => setIsPlaying(!isPlaying)}
          className="w-16 h-16 rounded-full bg-indigo-500 hover:bg-indigo-400 transition-colors flex items-center justify-center shrink-0 shadow-lg shadow-indigo-500/20"
        >
          {isPlaying ? <Pause fill="white" size={24} /> : <Play fill="white" className="ml-1" size={24} />}
        </button>

        <div className="flex-1">
          <div className="flex items-center gap-2 mb-1">
            <Sparkles size={14} className="text-indigo-400" />
            <span className="text-xs font-bold text-indigo-300 uppercase tracking-widest">AI Chief of Staff Briefing</span>
          </div>
          <h2 className="text-2xl font-bold mb-2 tracking-tight">{brief.title}</h2>
          <div className="flex items-center gap-4 text-slate-400 text-sm font-medium">
            <div className="flex items-center gap-1.5">
              <Volume2 size={14} />
              <span>{brief.duration} mins</span>
            </div>
            <span>•</span>
            <span>{brief.timestamp}</span>
          </div>
        </div>

        <div className="flex flex-wrap gap-2 md:max-w-xs justify-end">
          {brief.points.map((point, idx) => (
            <span key={idx} className="px-2 py-1 rounded bg-white/10 text-[10px] font-semibold border border-white/5 whitespace-nowrap">
              {point}
            </span>
          ))}
        </div>
      </div>

      {/* Expandable Transcript */}
      <div className="mt-6 border-t border-white/10 pt-4">
        <button 
          onClick={() => setShowTranscript(!showTranscript)}
          className="flex items-center gap-2 text-xs font-bold text-slate-400 hover:text-white transition-colors"
        >
          {showTranscript ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
