        </button>

        {showTranscript && (
          <div className="mt-4 text-sm text-slate-300 leading-relaxed font-normal bg-white/5 p-4 rounded-lg italic">
            "{brief.transcript}"
          </div>
        )}
      </div>
    </div>
  );
};

